    vector<int> maxScoreIndices(vector<int>& nums) {
        int n = nums.size();
        int maxScore = 0;
        vector<int> res;
        for (int i = 0; i <= n; i++) {
            int score = 0;
            for (int j = 0; j < i; j++) {
                if (nums[j] == 0) score++;
            }
            for (int j = i; j < n; j++) {
                if (nums[j] == 1) score++;
            }
            if (score > maxScore) {
                maxScore = score;
                res.clear();
                res.push_back(i);
            } else if (score == maxScore) {
                res.push_back(i);
            }
        }
        return res;
    }
};```
